module regamma(datain, dataout, load, initialize, clock);
input [4:0] datain;
input load, initialize;
input clock;
output [4:0] dataout;
reg [4:0] input_data;
always @(posedge clock)
begin
    if(initialize)
       input_data <= 5'b10000;
    else if(load)
       input_data <= datain;
    else
       input_data <= 5'b0;
end
assign dataout = input_data;
endmodule
